# Read the package data (MIT license, NPM)
package_file = locals()['var_functions.query_db:0']
with open(package_file, 'r') as f:
    packages = json.load(f)

# Filter for release packages
release_packages = []
for pkg in packages:
    version_info_str = pkg.get('VersionInfo', '')
    if 'IsRelease": true' in version_info_str:
        release_packages.append({
            'System': pkg['System'],
            'Name': pkg['Name'],
            'Version': pkg['Version']
        })

print('__RESULT__:')
print(json.dumps({
    'total_packages': len(packages),
    'release_packages': len(release_packages)
}))

